# Safe fillet with fallback
try:
    result = result.edges('|Z').fillet(radius)
except:
    pass  # Skip if radius too large

# Bolt circle pattern
result = (
    result.faces('>Z').workplane()
    .pushPoints([
        (r*math.cos(math.radians(a)), r*math.sin(math.radians(a)))
        for a in range(0, 360, 360//count)
    ])
    .hole(diameter)
)
